import{_ as a,o as s,c as e,a2 as r}from"./chunks/framework.N6Nd-M9-.js";const b=JSON.parse('{"title":"新人解惑：为什么不选择打电话、摆摊，而是选择面对面沟通","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/六大会议/01-公司为什么从外出作业开始——新人解惑.md","filePath":"notes/培训/六大会议/01-公司为什么从外出作业开始——新人解惑.md"}'),d={name:"notes/培训/六大会议/01-公司为什么从外出作业开始——新人解惑.md"};function c(i,t,n,p,o,l){return s(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="新人解惑-为什么不选择打电话、摆摊-而是选择面对面沟通" tabindex="-1">新人解惑：为什么不选择打电话、摆摊，而是选择面对面沟通 <a class="header-anchor" href="#新人解惑-为什么不选择打电话、摆摊-而是选择面对面沟通" aria-label="Permalink to &quot;新人解惑：为什么不选择打电话、摆摊，而是选择面对面沟通&quot;">​</a></h1><hr><h2 id="一、业务模式对比分析" tabindex="-1">一、业务模式对比分析 <a class="header-anchor" href="#一、业务模式对比分析" aria-label="Permalink to &quot;一、业务模式对比分析&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;margin:20px 0;"><div class="tc-card tc-card-blue"><p class="tc-blue tc-bold" style="margin:0 0 12px 0;font-size:18px;">📞 官方客服电话</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-blue tc-body"><strong>客户场景</strong>：有问题或投诉时才拨打</span><span class="tc-item tc-item-blue tc-body"><strong>业务特点</strong>：办理套餐多为标准价、高单价；短期优惠为主；客户被动接受</span><span class="tc-item tc-item-red tc-body"><strong>局限</strong>：平时根本不会接触到客服</span></div></div><div class="tc-card tc-card-green"><p class="tc-green tc-bold" style="margin:0 0 12px 0;font-size:18px;">📱 第三方电话销售</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-green tc-body"><strong>目标客户</strong>：本网用户</span><span class="tc-item tc-item-green tc-body"><strong>业务内容</strong>：推销套餐、流量包、合约等增值业务</span><span class="tc-item tc-item-red tc-body"><strong>痛点</strong>：限制多，拒绝率高；大海捞针式营销；日均拨打上千电话</span></div></div><div class="tc-card tc-card-orange"><p class="tc-orange tc-bold" style="margin:0 0 12px 0;font-size:18px;">🏢 营业厅服务</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-orange tc-body"><strong>服务范围</strong>：主要针对本网客户</span><span class="tc-item tc-item-green tc-body"><strong>优势</strong>：权限较高</span><span class="tc-item tc-item-red tc-body"><strong>局限</strong>：跨网客户几乎不会主动上门</span></div></div></div><hr><h2 id="二、我们的核心优势-面对面沟通" tabindex="-1">二、我们的核心优势：面对面沟通 <a class="header-anchor" href="#二、我们的核心优势-面对面沟通" aria-label="Permalink to &quot;二、我们的核心优势：面对面沟通&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin:20px 0;"><div class="tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);padding:18px;border-radius:12px;"><p style="font-size:28px;margin:0 0 8px 0;">⚡</p><p class="tc-blue tc-bold" style="font-size:15px;margin:0;">即时专业</p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">当面解决客户所有问题<br>响应速度优于线上客服</p></div><div class="tc-center" style="background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.15);padding:18px;border-radius:12px;"><p style="font-size:28px;margin:0 0 8px 0;">📋</p><p class="tc-green tc-bold" style="font-size:15px;margin:0;">方案优化</p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">推荐更多优惠、合理的套餐方案<br>基于客户实际需求定制</p></div><div class="tc-center" style="background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.15);padding:18px;border-radius:12px;"><p style="font-size:28px;margin:0 0 8px 0;">🌐</p><p class="tc-orange tc-bold" style="font-size:15px;margin:0;">全覆盖无界限</p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">可接触四大运营商所有客户<br>无运营商局限性</p></div><div class="tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);padding:18px;border-radius:12px;"><p style="font-size:28px;margin:0 0 8px 0;">✅</p><p class="tc-red tc-bold" style="font-size:15px;margin:0;">高效办理</p><p class="tc-body tc-sm" style="margin:8px 0 0 0;">业务当场办理完成<br>转化效率高</p></div></div><hr><h2 id="三、个人成长价值" tabindex="-1">三、个人成长价值 <a class="header-anchor" href="#三、个人成长价值" aria-label="Permalink to &quot;三、个人成长价值&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:16px;margin:20px 0;"><p class="tc-blue tc-bold" style="margin:0 0 15px 0;font-size:16px;">💬 销售的本质：学习沟通</p><blockquote class="tc-body" style="margin:0 0 15px 0;padding:15px 20px;background:rgba(102,126,234,0.08);border-left:4px solid #667eea;border-radius:0 8px 8px 0;font-size:14px;">&quot;不论在职场、官场还是其他工作，都少不了与人沟通&quot; </blockquote><p class="tc-body" style="margin:0 0 10px 0;font-size:14px;">对比其他行业模式：</p><table tabindex="0"><thead><tr><th>行业</th><th>业务员职责</th><th>谈判权限</th></tr></thead><tbody><tr><td>律师事务所</td><td>只负责约顾客</td><td>销售代表谈判</td></tr><tr><td>保险行业</td><td>只负责约业务</td><td>销售负责谈业务</td></tr><tr><td>银行贷款</td><td>只负责约业务</td><td>销售负责谈业务</td></tr><tr><td>医疗销售</td><td>负责堵人、约人</td><td>专人负责谈判</td></tr></tbody></table><p class="tc-muted tc-sm" style="margin:15px 0 0 0;">💡 现实案例：隔壁公司经理以前就做过医疗销售，曾为学习谈判，在工具包下放录音笔偷录学习过程</p></div><hr><h2 id="四、我们的独特机会" tabindex="-1">四、我们的独特机会 <a class="header-anchor" href="#四、我们的独特机会" aria-label="Permalink to &quot;四、我们的独特机会&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;margin:20px 0;"><div class="tc-card tc-card-blue"><p class="tc-blue tc-bold" style="margin:0 0 12px 0;font-size:18px;">🌟 全程参与</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-blue tc-body">不仅约人，更参与全程沟通</span><span class="tc-item tc-item-blue tc-body">直接积累谈判经验</span><span class="tc-item tc-item-blue tc-body">避免&quot;只做方案不出场&quot;的职场困境</span></div></div><div class="tc-card tc-card-green"><p class="tc-green tc-bold" style="margin:0 0 12px 0;font-size:18px;">👥 多元客户群体</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-green tc-body">企业老板</span><span class="tc-item tc-item-green tc-body">市井小民</span><span class="tc-item tc-item-green tc-body">单位领导、地方管理</span></div></div><div class="tc-card tc-card-orange"><p class="tc-orange tc-bold" style="margin:0 0 12px 0;font-size:18px;">🚀 全方位能力培养</p><div style="display:flex;flex-direction:column;gap:8px;"><span class="tc-item tc-item-orange tc-body"><strong>察言观色</strong></span><span class="tc-item tc-item-orange tc-body"><strong>人情世故</strong></span><span class="tc-item tc-item-orange tc-body"><strong>场景应变</strong> · <strong>谈判技巧</strong></span></div></div></div><hr><h2 id="五、不可替代的成长体验" tabindex="-1">五、不可替代的成长体验 <a class="header-anchor" href="#五、不可替代的成长体验" aria-label="Permalink to &quot;五、不可替代的成长体验&quot;">​</a></h2><div style="background:linear-gradient(135deg,rgba(102,126,234,0.1) 0%,rgba(34,197,94,0.1) 100%);border:2px solid rgba(102,126,234,0.2);padding:25px;border-radius:16px;margin:20px 0;"><blockquote class="tc-body tc-bold" style="margin:0 0 20px 0;padding:15px 20px;background:rgba(255,255,255,0.6);border-left:4px solid #667eea;border-radius:0 8px 8px 0;font-size:15px;">&quot;这些都是学校不会教你的东西&quot; </blockquote><div style="display:flex;flex-direction:column;gap:10px;"><span class="tc-sub tc-body">✨ 在市场上见识各种各样的人</span><span class="tc-sub tc-body">✨ 经历各种各样的事</span><span class="tc-sub tc-body">✨ 学习真正有用的社会能力</span></div></div><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div class="tc-center" style="background:linear-gradient(135deg,rgba(239,68,68,0.1) 0%,rgba(245,158,11,0.1) 100%);border:2px solid rgba(239,68,68,0.2);padding:25px;border-radius:16px;margin:20px 0;"><p class="tc-body" style="margin:0 0 15px 0;font-size:16px;line-height:1.8;"> 我们的<strong class="tc-red">面对面沟通模式</strong>在业务层面更具效率和针对性，<br> 在个人层面提供<strong class="tc-orange">快速成长和核心能力积累</strong>的宝贵机会。 </p><p class="tc-blue tc-bold" style="margin:0;font-size:18px;"> 这不仅仅是一份工作，更是一个成长平台。 </p></div>',19)])])}const x=a(d,[["render",c]]);export{b as __pageData,x as default};
